mapper.select:
SELECT * FROM ( SELECT ROWNUM RN, I.* FROM ( SELECT item_id AS itemId, item_name AS itemName, item_type AS itemType, item_unit AS unit, item_spec AS spec, item_unit_price AS unitPrice, item_storage AS itemStorage, item_vendor AS itemVendor, item_usedate AS useDate, item_safety_stock AS safetyStock, item_usage AS itemUsage FROM item
and item_type = #{searchType}
and (upper(item_name) like upper(('%' || #{searchKeyword} || '%'))) or (upper(item_id) like upper(('%' || #{searchKeyword} || '%')))
and item_usage = 'Y'
ORDER BY item_id DESC ) I ) WHERE RN BETWEEN #{page.startRow} AND #{page.endRow}
